// Расчёт статистики отжиманий
const challengeStart = new Date('2025-10-25');
const now = new Date();
const dayNumber = Math.floor((now - challengeStart) / (24 * 60 * 60 * 1000)) + 1;
const pushupCount = 10 + (dayNumber - 1);
const yearEndCount = 10 + 364;
const daysLeft = 365 - dayNumber;
const progress = (dayNumber / 365 * 100).toFixed(1);
const progressBar = '█'.repeat(Math.floor(progress / 5)) + '░'.repeat(20 - Math.floor(progress / 5));

// Всего отжиманий сделано (сумма 10+11+...+pushupCount)
const totalDone = dayNumber * 10 + (dayNumber * (dayNumber - 1)) / 2;

return [{
  json: {
    day: dayNumber,
    count: pushupCount,
    year_end: yearEndCount,
    days_left: daysLeft,
    progress: progress,
    progress_bar: progressBar,
    total_done: totalDone.toLocaleString('ru-RU')
  }
}];
